INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Dataset catalog & search$q$, $q$A searchable, filterable web catalog where datasets are registered with structured metadata, tags, and organization ownership.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$RESTful Action API$q$, $q$A JSON API for programmatically creating, querying, and managing datasets, resources, and organizations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Resource previews & visualizations$q$, $q$Built-in previews and simple charts (bar, line, pie) and maps for tabular and geospatial data resources.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$DataStore & DataPusher$q$, $q$Extensions that load tabular data into a queryable database so it can be filtered and accessed via API, not just downloaded.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Extension ecosystem$q$, $q$Over 60 community-built extensions covering harvesting, analytics, theming, authentication, and more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Federated portals$q$, $q$Multiple CKAN instances can share and aggregate datasets across a network of connected portals.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Role-based access control$q$, $q$User and organization management with configurable permissions for publishing and editing datasets.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Mature, widely adopted by national government open-data portals$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Strong, well-documented API for automation and integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Highly extensible via a large plugin ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Requires server administration and database/search-index expertise to self-host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$No official managed SaaS product directly from the CKAN project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$User interface is functional but dated compared to modern commercial data-catalog tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Deployment and upgrades can be technically demanding at larger scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Is CKAN free to use?$q$, $q$Yes. CKAN is open-source software released under the AGPL-3.0 license, so there is no fee to download, modify, or self-host it. Costs come from hosting infrastructure and any optional third-party support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Who typically uses CKAN?$q$, $q$Government agencies, research institutions, NGOs, and other organizations that need to publish structured datasets publicly or internally, including operators of national open-data portals such as data.gov and data.gov.uk.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Does CKAN offer official hosting?$q$, $q$The CKAN project itself does not sell hosting. Organizations either self-host on their own infrastructure or contract third-party vendors, such as Datopian or Link Digital, for managed CKAN hosting and support.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Can CKAN be customized?$q$, $q$Yes. CKAN has a modular extension system with more than 60 publicly available extensions covering harvesting, visualization, theming, and more, and organizations can also build custom extensions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$What technical stack does CKAN use?$q$, $q$CKAN is built in Python, uses PostgreSQL for data storage, and uses Apache Solr for search indexing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Is CKAN suitable for a small team without DevOps resources?$q$, $q$It can be challenging without technical expertise, since self-hosting requires managing servers, a database, and a search index; smaller teams often use a managed-hosting vendor instead.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Government open-data portals$q$, $q$Publishing public-sector datasets in a searchable catalog with standardized metadata and an API for reuse.$q$, $q$Government agencies and public-sector data teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Research data repositories$q$, $q$Cataloging and sharing research datasets with structured metadata and version tracking across institutions.$q$, $q$Universities and research organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Humanitarian and NGO data sharing$q$, $q$Aggregating and distributing datasets across humanitarian organizations, as used by platforms like the Humanitarian Data Exchange.$q$, $q$NGOs and international organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$Self-Hosted Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CKAN source code and core platform","Community support via GitHub and forums","Requires own server and hosting infrastructure","AGPL-3.0 licensed"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CKAN is a free, open-source data management system built to power open-data portals and data catalogs. Originating from the Open Knowledge Foundation in the mid-2000s, it has become one of the most widely used platforms behind government open-data initiatives, including data.gov and data.gov.uk.$q$, $q$Rather than being sold as a hosted product, CKAN is self-hosted software: organizations install it on their own infrastructure or work with a third-party vendor for managed hosting and support. It is written in Python, backed by PostgreSQL for storage and Solr for search, and released under the AGPL-3.0 open-source license.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, CKAN lets publishers register datasets with rich metadata, attach or link data files in formats like CSV, Excel, GeoJSON, and PDF, and expose everything through a searchable, filterable public catalog.$q$, $q$A RESTful JSON Action API gives developers programmatic access to datasets, organizations, and search, making CKAN suitable for automated pipelines and third-party integrations rather than just manual browsing.$q$, $q$Extensions вЂ” more than 60 are publicly available вЂ” add capabilities such as harvesting datasets from other catalogs, a queryable DataStore for tabular data, analytics, custom theming, and federation between multiple CKAN portals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CKAN's software has no license fee: the source code is free to download, modify, and self-host under the AGPL-3.0 license. The real cost of running CKAN comes from infrastructure (servers, database, search index) and, optionally, support or managed hosting contracts from vendors such as Datopian or Link Digital.$q$, $q$There is no official paid tier or managed SaaS offering from the CKAN project or the Open Knowledge Foundation, so organizations evaluating CKAN should budget for either in-house DevOps capacity or a third-party hosting partner.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e8f32075-0ef5-42f6-8b94-a8c3c8544c46', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Static image analysis$q$, $q$Scans container image layers for installed packages without executing the container.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Multi-distribution CVE matching$q$, $q$Checks packages against vulnerability data covering RHEL, Alpine, Ubuntu, Debian, Oracle Linux, Photon OS, and SUSE.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Language ecosystem coverage$q$, $q$Detects vulnerable dependencies in Java, Python, Go, and JavaScript packages inside images.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Continuous re-scanning$q$, $q$Re-checks previously indexed images against newly published vulnerabilities without requiring a fresh upload.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Webhook notifications$q$, $q$The notifier component fires webhooks when a scanned image gains new CVE matches.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$REST and gRPC API$q$, $q$Exposes indexing and matching functionality programmatically for integration into registries and pipelines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Flexible deployment$q$, $q$Runs as microservices, a monolith, in CI pipelines, or in disconnected/air-gapped environments.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Free and open source under Apache 2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Proven at scale as the scanning engine behind Quay.io$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Broad coverage across major Linux distributions and language ecosystems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Flexible deployment options, including air-gapped environments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$No official managed cloud version; requires self-hosting and operational investment$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Setup and datastore management require DevOps/security engineering expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$No built-in dashboard for non-technical users beyond what integrating tools provide$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Best experienced when paired with a registry like Quay rather than used fully standalone$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Is Clair free to use?$q$, $q$Yes. Clair is open-source software licensed under Apache 2.0, so it can be downloaded, run, and modified at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$What does Clair actually scan?$q$, $q$Clair statically analyzes container image layers, identifying installed OS packages and language dependencies, then matches them against vulnerability databases covering multiple Linux distributions and language ecosystems.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Who maintains Clair today?$q$, $q$Clair originated at CoreOS and has been maintained primarily under Red Hat's stewardship since Red Hat acquired CoreOS in 2018; development happens in the open on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Does Clair require a container registry like Quay?$q$, $q$No, Clair can run standalone via its API, but it is most commonly deployed as the scanning backend for a registry, most notably Red Hat Quay and Quay.io.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Can Clair be used in CI/CD pipelines?$q$, $q$Yes, Clair's API-driven, microservice-friendly design makes it suitable for integration into CI/CD pipelines to flag or block images with known vulnerabilities.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Container registry security scanning$q$, $q$Acting as the scanning backend for a private or public container registry, continuously checking stored images for known CVEs.$q$, $q$Platform engineering and registry operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$CI/CD pipeline security gates$q$, $q$Scanning images during the build pipeline to catch known-vulnerable packages before deployment.$q$, $q$DevSecOps and application engineering teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under Apache 2.0","Self-hosted deployment as microservices or monolith","Community support via GitHub","No usage limits imposed by the project itself"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clair is a free, open-source vulnerability scanner for container images. It was first announced by CoreOS in November 2015 and is now maintained as Project Clair, primarily developed within the quay/clair GitHub organization under Red Hat's stewardship after Red Hat's 2018 acquisition of CoreOS.$q$, $q$Clair performs static analysis: it inspects the packages and libraries inside a container image and checks them against continuously updated vulnerability databases, rather than executing the container to observe runtime behavior.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clair indexes container image layers to identify installed packages across major Linux distributions (RHEL, Alpine, Ubuntu, Debian, Oracle Linux, Photon OS, SUSE) and common language ecosystems (Java, Python, Go, JavaScript), then matches them against known-vulnerability data.$q$, $q$Its v4 architecture separates concerns into an indexer, a matcher, a notifier (for webhook-based alerts on new CVE matches against previously scanned images), and a REST/gRPC API, and it can be deployed as microservices, as a more monolithic setup, or embedded in CI pipelines and disconnected environments.$q$, $q$Clair is the vulnerability-scanning engine behind Red Hat Quay and the public Quay.io registry, continuously re-evaluating stored images as new vulnerabilities become known.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clair is free and open source under the Apache 2.0 license, with no cost to download, deploy, or modify. There is no official paid or managed version sold directly by the project.$q$, $q$Organizations that don't want to operate Clair themselves typically consume it indirectly through a product that embeds it, such as Red Hat Quay, which has its own commercial and hosted offerings.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('caec6253-7f1b-408d-968e-1099f0367648', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$AI-assisted forecasting$q$, $q$Analyzes CRM, email, and calendar activity to produce revenue forecasts and flag at-risk deals.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Pipeline inspection$q$, $q$Gives managers and executives a real-time, rollup view of pipeline health across teams and regions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Conversation intelligence (Copilot)$q$, $q$Records, transcribes, and analyzes sales calls to surface deal risk, competitor mentions, and coaching opportunities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Mutual action plans (Align)$q$, $q$Shared workspaces where sellers and buyers track next steps, timelines, and requirements together.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Sales engagement automation (Groove)$q$, $q$Email and call cadence automation for outbound prospecting and pipeline generation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$CRM integration$q$, $q$Syncs with Salesforce and other systems so forecast and pipeline data stay current without manual entry.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$RevOps analytics$q$, $q$Dashboards and reporting built for revenue operations and executive-level visibility into the sales funnel.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Consolidates forecasting, deal inspection, and conversation intelligence in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Strong fit for large, complex enterprise sales organizations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$AI-driven deal-risk scoring reduces reliance on manual spreadsheet forecasting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Backed by significant funding and a large existing enterprise customer base$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$No public pricing; requires a sales process to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Can be costly at scale, especially when combining multiple modules$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Implementation and professional-services costs add to total cost of ownership$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Primarily built for enterprise teams, less suited to small sales organizations$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$How much does Clari cost?$q$, $q$Clari does not publish pricing publicly. Costs depend on which modules (Forecast, Copilot, Align, Groove) are purchased, seat count, and negotiated enterprise terms, so buyers need to request a quote.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$What is Clari Copilot?$q$, $q$Clari Copilot is Clari's conversation-intelligence product, providing call recording, transcription, and AI-generated summaries and coaching insights from sales calls.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Does Clari integrate with Salesforce?$q$, $q$Yes, Clari integrates with major CRM platforms, principally Salesforce, syncing pipeline and deal data to power its forecasting and inspection features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Who is Clari built for?$q$, $q$Clari is built for enterprise B2B sales, revenue operations, and executive teams that need consolidated forecasting and pipeline visibility, rather than individual sellers or small teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$When was Clari founded?$q$, $q$Clari was founded in 2013 by Andy Byrne and Venkat Rangan and is headquartered in Sunnyvale, California.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Revenue forecasting$q$, $q$Replacing manual, spreadsheet-based forecast rollups with AI-assisted, continuously updated forecasts.$q$, $q$Sales leadership and revenue operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Sales call coaching$q$, $q$Reviewing recorded and transcribed sales calls to coach reps and surface deal risk earlier.$q$, $q$Sales managers and enablement teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$Complex enterprise deal management$q$, $q$Using shared mutual action plans to keep multi-stakeholder buyer-seller deals aligned on next steps.$q$, $q$Enterprise account executives and buying committees$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clari is an enterprise revenue orchestration platform founded in 2013 by Andy Byrne and Venkat Rangan and headquartered in Sunnyvale, California. It combines forecasting, pipeline inspection, conversation intelligence, and deal-execution tools into a single system for large B2B sales organizations.$q$, $q$The company has raised substantial venture funding, including a 2022 Series F round led by Blackstone and Silver Lake that valued the business at approximately $2.6 billion, and serves enterprise customers across industries that rely on predictable, forecastable recurring revenue.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clari Forecast, the platform's original core module, uses AI-assisted analysis of CRM, email, and calendar data to surface deal risk and produce more accurate, less manual revenue forecasts than spreadsheet-based rollups.$q$, $q$Clari Copilot adds conversation intelligence вЂ” call recording, transcription, and AI-generated summaries and coaching вЂ” while Clari Align provides shared mutual action plans for buyer-seller collaboration on complex deals, and Clari Groove adds outbound email/call cadence automation.$q$, $q$The platform integrates with major CRMs (principally Salesforce) and sales communication tools, giving revenue leaders a consolidated, continuously updated view of pipeline health rather than a static end-of-quarter report.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clari does not publish self-serve pricing. Every deployment is quoted individually based on which modules (Forecast, Copilot, Align, Groove) are purchased, seat count, and negotiated enterprise terms.$q$, $q$Third-party pricing analyses suggest per-module costs commonly fall in the $60-$125 per user, per month range, with combined multi-module deployments running higher, plus separate implementation and professional-services fees for enterprise rollouts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6c40226a-eb4f-4492-897b-fa93c0ac4f4c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Conversational AI chat$q$, $q$Web and mobile chat interface for research, writing, brainstorming, and general question answering.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Claude Code$q$, $q$An agentic coding tool that lets Claude read, edit, and run code across a codebase from a terminal or IDE.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Multiple model tiers$q$, $q$A range of Claude models balancing speed/cost against reasoning depth, selectable by plan and use case.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Persistent memory$q$, $q$Retains context across conversations so Claude can reference prior discussions without re-explaining.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Web search$q$, $q$Built-in ability to search the web for up-to-date information within a conversation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Developer API$q$, $q$Usage-based API access to Claude models for building custom applications, also available via Amazon Bedrock and Google Cloud Vertex AI.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise administration$q$, $q$SSO, SCIM, audit logs, role-based access, and configurable data retention for large organizations.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Free tier available alongside multiple paid tiers for different usage levels$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Strong coding and agentic-task capabilities via Claude Code$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise-grade compliance and admin features (SSO, SCIM, audit logs)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Available across web, desktop, mobile, and API, plus major cloud marketplaces$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Usage limits on Free and Pro tiers can be restrictive for heavy users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Max and Enterprise tiers are significantly more expensive than entry-level plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$API costs scale with token usage and can be harder to predict than flat subscriptions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise pricing is not published and requires a custom quote$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Is Claude free to use?$q$, $q$Yes, Anthropic offers a free tier of Claude with usage limits for chat, code generation, content creation, and web search on web and mobile.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$What is Claude Code?$q$, $q$Claude Code is Anthropic's agentic coding tool that lets Claude read, edit, and run code across a project from a terminal or IDE, included with Pro and higher plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$How much does Claude Pro cost?$q$, $q$Claude Pro is $17/month when billed annually, or $20/month when billed monthly, and includes higher usage limits and access to Claude Code.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Can businesses use Claude?$q$, $q$Yes, Anthropic offers Team plans for groups of roughly 2-150 people and custom-quoted Enterprise plans with SSO, SCIM, audit logs, and compliance features for larger organizations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Who founded Anthropic?$q$, $q$Anthropic was founded in January 2021 by Dario Amodei and Daniela Amodei, along with several other former OpenAI researchers, and is headquartered in San Francisco.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Is there an API for developers?$q$, $q$Yes, Claude models are available through Anthropic's own API on a usage-based, pay-per-token basis, and are also accessible through Amazon Bedrock and Google Cloud Vertex AI.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Everyday knowledge work$q$, $q$Using Claude's chat interface for writing, research, summarization, and brainstorming.$q$, $q$Individual professionals and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Agentic software development$q$, $q$Using Claude Code to read, write, and run code across a codebase for multi-step development tasks.$q$, $q$Software developers and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise AI deployment$q$, $q$Building regulated or large-scale AI applications with SSO, audit logs, and compliance controls via Enterprise plans or the API.$q$, $q$Enterprises and regulated organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Web and mobile chat","Code generation and content creation","Web search and memory","File creation","Usage limits apply"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Pro$q$, $q$$17/month (annual) or $20/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Free with higher usage limits","Claude Code access","Unlimited projects","Research features","Access to multiple Claude models"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Max$q$, $q$From $100/month$q$, $q$Monthly$q$, NULL, $q$["5x or 20x more usage than Pro","Higher output limits","Early access to advanced features","Priority access during peak traffic"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Team$q$, $q$$20-25/month per standard seat; $100-125/month per premium seat$q$, $q$Monthly or annual$q$, NULL, $q$["For teams of 2-150 people","SSO and admin controls","Central billing","Compliance features"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Seats plus API usage pricing","SCIM and audit logs","Role-based access control","Configurable data retention","HIPAA-ready options","IP allowlisting"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Claude is the AI assistant product built by Anthropic, an AI safety and research company founded in 2021 by Dario Amodei and Daniela Amodei and headquartered in San Francisco. Claude is available as a free consumer chat app on web and mobile, as desktop apps, and as a usage-based API for developers building their own products.$q$, $q$Anthropic offers Claude in multiple model families spanning different speed, cost, and capability levels, used both inside Anthropic's own apps (including the agentic coding tool Claude Code) and by third-party developers accessing the models directly or through cloud partners like Amazon Bedrock and Google Cloud Vertex AI.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Claude's consumer apps support conversational chat, code generation, content creation, web search, persistent memory across conversations, and file creation, with paid tiers unlocking higher usage limits and additional tools.$q$, $q$Claude Code extends Claude into agentic software development, letting it read and edit files, run commands, and carry out multi-step coding tasks from a terminal or IDE rather than answering isolated prompts.$q$, $q$For organizations, Team and Enterprise plans add centralized billing, admin controls, SSO and SCIM provisioning, audit logs, configurable data retention, and compliance features aimed at regulated industries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Claude offers a free tier with usage limits, a Pro plan at $17/month billed annually ($20/month billed monthly) with higher limits and access to Claude Code, and a Max plan starting at $100/month for substantially higher usage caps and priority access.$q$, $q$Team plans run $20-25/month per standard seat or $100-125/month per premium seat for organizations of roughly 2-150 people, while Enterprise pricing is custom-quoted based on seat count and API usage. Developers can also access Claude models directly through Anthropic's API on a pay-per-token basis.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4648f65b-d55e-4ed8-ad0d-c40b3343b03c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
