INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Spreadsheet-style workflow builder$q$, $q$Table interface where each row is a record and each column runs an enrichment or automation step, usable without code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$100+ data provider waterfalls$q$, $q$Combines multiple third-party data sources per record to maximize enrichment match rates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Claygent AI research agent$q$, $q$An AI agent that browses the web to find and extract specific information into a table column.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Signal and job-change tracking$q$, $q$Monitors buying signals and job changes to surface timely outbound opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$CRM auto-sync$q$, $q$Keeps enriched data synced automatically with CRM systems on higher-tier plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$HTTP API & webhook integrations$q$, $q$Connects Clay workflows to external systems and custom applications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Ad-platform audience pushes$q$, $q$Sends enriched, segmented audiences directly to advertising platforms for targeted campaigns.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Combines 100+ data sources in a single, unified workflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$AI research agent (Claygent) automates manual lookup tasks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$No-code, spreadsheet-familiar interface lowers the barrier to complex workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Free plan available for evaluating the platform before committing to a paid tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Credit-based pricing can become expensive and hard to predict at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Paid plans jump significantly in price between tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Learning curve for building advanced multi-step workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Effective use often requires understanding of the many underlying data providers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Is Clay free to use?$q$, $q$Clay offers a Free plan with 500 actions and 100 data credits per month and unlimited seats, suitable for evaluating the platform before upgrading to a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$What is Claygent?$q$, $q$Claygent is Clay's AI research agent that can browse the web and extract specific information into a table column, automating manual research tasks.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$How does Clay's pricing work?$q$, $q$Clay uses a credit-based model combining 'actions' (workflow steps) and 'data credits' (enrichment lookups), with monthly allowances that scale up across the Free, Launch, Growth, and Enterprise plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Do I need to code to use Clay?$q$, $q$No, Clay is designed as a no-code, spreadsheet-style tool where workflows are built by chaining together enrichment columns, formulas, and integrations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Who is Clay built for?$q$, $q$Clay is built for go-to-market, sales development, and revenue operations teams that need to combine data sources and automate outbound prospecting and personalization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$When was Clay founded?$q$, $q$Clay was founded in 2017 by Kareem Amin and Nicolae Rusan, with Varun Anand joining as a co-founder in 2021, and is headquartered in New York City.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Outbound lead enrichment$q$, $q$Combining multiple data providers to build accurate, up-to-date contact and account records for outbound sales.$q$, $q$Sales development representatives and outbound teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Signal-based prospecting$q$, $q$Tracking job changes and buying signals to identify and reach prospects at the right moment.$q$, $q$Growth and demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Personalized outreach automation$q$, $q$Using AI research to personalize outbound messaging at scale before syncing to a CRM or sequencing tool.$q$, $q$RevOps and marketing operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["500 actions/month","100 data credits/month","Unlimited seats","Up to 200 rows per table","Claygent enrichment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Launch$q$, $q$From ~$149-185/month$q$, $q$Monthly or annual$q$, NULL, $q$["~15,000 actions/month","~3,000 data credits/month","Phone number enrichment","Job-change and signal tracking","Up to 50,000 rows per table"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Growth$q$, $q$From ~$446-495/month$q$, $q$Monthly or annual$q$, NULL, $q$["~40,000 actions/month","~6,000 data credits/month","CRM auto-sync","HTTP API & webhook integrations","Ad-platform audience pushes"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["200,000+ actions/month","Unlimited ad audiences","SSO and RBAC","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Clay is a go-to-market data and automation platform founded in 2017 by Kareem Amin and Nicolae Rusan, with Varun Anand joining as a co-founder in 2021, and headquartered in New York City. It has evolved from a general-purpose data workflow tool into a platform purpose-built for sales, marketing, and RevOps teams doing prospecting and enrichment.$q$, $q$The product centers on a spreadsheet-like table interface, where each row is a record (person, company, or account) and each column runs a data or automation step, letting non-technical users build complex, multi-source enrichment workflows without writing code.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Clay connects to more than 100 third-party data providers covering firmographic, technographic, contact, and intent/signal data, letting users combine multiple sources per record instead of relying on a single vendor.$q$, $q$Claygent, Clay's AI research agent, can browse the web and extract specific pieces of information into a table column, effectively automating manual research tasks that would otherwise require a human to look things up individually.$q$, $q$Beyond enrichment, Clay supports action steps such as CRM syncing, email campaign integrations, webhook automation, and pushing audiences directly to ad platforms, making it a workflow tool rather than a pure data provider.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Clay uses a freemium, credit-based pricing model. The Free plan includes 500 actions and 100 data credits per month with unlimited seats, while paid plans (Launch, Growth, and Enterprise) scale up action and data-credit allowances alongside additional features like CRM auto-sync and ad-audience pushes.$q$, $q$Paid plans start around $149-185/month for Launch and roughly $446-495/month for Growth, depending on billing term and credit volume, with Enterprise pricing custom-quoted for large-scale usage.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c5a72856-c532-4882-bce1-c4c3664d929b', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Browser-based recording$q$, $q$Records remote interviews directly in a web browser with no app download required for guests.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Multitrack recording$q$, $q$Captures each participant as a separate, synced WAV file at up to 48kHz for cleaner post-production.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Noise removal & echo cancellation$q$, $q$Built-in audio processing to reduce background noise and echo during and after recording.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Low-latency peer-to-peer audio$q$, $q$Uses direct browser-to-browser connections rather than a media server, reducing lag during live conversation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Channel mixer$q$, $q$Live mixing controls for adjusting participant audio levels during a session.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Studio tools$q$, $q$Built-in intros, idents, and jingle beds for produced, broadcast-style output.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Privacy & invite controls$q$, $q$Personalized, controlled invite links for guests joining a recording session.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$No app download required for guests to join a recording$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Low-latency, browser-based peer-to-peer audio connections$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Free Lite tier supports commercial use with unlimited recording length$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Trusted by major broadcasters like the BBC and NPR$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Free tier caps sessions at three participants$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Focused on audio only, without built-in video recording features some competitors offer$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Advanced production and repurposing features are more limited than some newer podcast-first platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Multitrack recording and higher-quality audio require the paid Pro tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Is Cleanfeed free to use?$q$, $q$Yes, Cleanfeed Lite is a free tier supporting browser-based remote recording for up to three participants with unlimited recording length and commercial use permitted.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Do guests need to install anything to join a Cleanfeed session?$q$, $q$No, guests join through a web browser via a link, with no app download, plugin, or account required on their end.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$What does Cleanfeed Pro add over the free plan?$q$, $q$Pro adds multitrack recording with separate WAV files per participant, noise removal and echo cancellation, audio repair, a channel mixer, support for more than three participants, and studio tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Who uses Cleanfeed?$q$, $q$Cleanfeed is used by broadcasters including the BBC and NPR, as well as independent podcasters and commercial audio production houses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Does Cleanfeed offer team or organization pricing?$q$, $q$Yes, an Enterprise/Education tier is available for organizations needing five or more Cleanfeed Pro licenses, with consolidated billing and branding options via direct contact.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Podcast remote interviews$q$, $q$Recording remote guest interviews in broadcast-quality audio without requiring guests to install software.$q$, $q$Independent podcasters and podcast producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Radio and broadcast production$q$, $q$Capturing remote contributor audio for radio broadcast with low latency and reliable audio fidelity.$q$, $q$Radio stations and broadcast newsrooms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Commercial audio production$q$, $q$Recording voiceover or interview sessions with remote talent for commercial audio projects.$q$, $q$Audio production studios and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Cleanfeed Lite$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 3 participants","Unlimited recording length","Commercial use permitted","Basic feature set"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Cleanfeed Pro$q$, $q$$12-23/month (varies by billing term and discount)$q$, $q$Monthly or annual$q$, NULL, $q$["Multitrack recording (synced WAV per participant)","Noise removal & echo cancellation","Audio repair","Channel mixer","Support for more than 3 participants","Studio tools (intros, idents, jingle beds)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$Enterprise & Education$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["5+ Cleanfeed Pro licenses","Consolidated billing","Custom invoicing","Branding options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cleanfeed is a browser-based remote audio recording platform built for broadcast-quality podcast and radio interviews. Founded by Mark Hills and Marc Bakos and headquartered in London, the company has been used by major broadcasters such as the BBC and NPR as well as independent podcasters and commercial production studios.$q$, $q$Rather than requiring guests to download an app, Cleanfeed uses direct browser-to-browser audio connections, so a host can send a link and start recording with a remote guest with no software installation on the guest's end.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cleanfeed Pro supports multitrack recording, capturing each participant as a separate, synced WAV file at up to 48kHz, along with noise removal, echo cancellation, and audio repair tools for cleaning up problem recordings.$q$, $q$Additional Pro features include a live channel mixer, higher-bitrate encoding (up to 256kbps mono or 320kbps stereo), studio tools like intros, idents, and jingle beds, and privacy controls with personalized guest invite links.$q$, $q$Cleanfeed Lite, the free tier, supports unlimited-length recordings for up to three participants with commercial use permitted, making it usable for basic remote interviews without a subscription.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cleanfeed offers a free Lite plan (up to 3 participants, unlimited recording length) and a paid Pro plan priced from roughly $12/month on annual billing up to around $23-36/month depending on billing term and discount eligibility (education, charity, or personal use).$q$, $q$An Enterprise/Education tier is available for organizations needing five or more Pro licenses, with consolidated billing and branding options available through direct contact with Cleanfeed's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b313f97-5726-4dc3-822e-2919a68cf2b3', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Annotation tools$q$, $q$Arrows, text, shapes, and blur/pixelation tools for marking up screenshots.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Scrolling capture$q$, $q$Automatically captures full-length web pages or documents beyond the visible screen area.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Built-in OCR$q$, $q$Extracts editable text directly from a screenshot without a separate tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Screen recording$q$, $q$Records the screen as a video file or an optimized, shareable GIF.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Smart blur$q$, $q$AI-based detection and redaction of sensitive information like emails and card numbers in a capture.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Quick-access overlay$q$, $q$A floating panel appears after each capture for immediate annotation, copy, or sharing actions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$CleanShot Cloud sharing$q$, $q$Uploads captures to shareable links with optional password protection, expiration, and custom domain branding.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$One-time purchase option instead of a mandatory subscription for the core app$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Extensive annotation and AI-assisted editing tools beyond macOS's default screenshot tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Scrolling capture and OCR built directly into the app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$30-day money-back guarantee reduces purchase risk$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Mac-only; no Windows version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$No official company background or founding date published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Unlimited cloud storage and team features require an ongoing Cloud Pro subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Update access beyond the first year requires an annual renewal fee$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$How much does CleanShot X cost?$q$, $q$The core Mac app is a one-time $29 lifetime license per Mac, including one year of free updates, with an optional $19/year renewal for continued updates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Is CleanShot X available on Windows?$q$, $q$No, CleanShot X is built exclusively for macOS and requires macOS 10.15 or newer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$What is CleanShot Cloud?$q$, $q$CleanShot Cloud is an optional hosting and sharing service for screenshots, GIFs, and videos, with a Basic tier bundled into the app purchase and a paid Pro tier for unlimited storage and team features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Is there a free trial of CleanShot X?$q$, $q$There is no dedicated standalone free trial, but purchases are covered by a 30-day money-back guarantee, and the app can also be tried through a Setapp subscription trial.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Who makes CleanShot X?$q$, $q$CleanShot X is developed by Luke Oslizlo and a small team based in Poland; the company does not publish detailed corporate background information.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Product design & QA feedback$q$, $q$Capturing and annotating screenshots to report bugs or share visual feedback with a team.$q$, $q$Designers, developers, and QA testers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Documentation & tutorials$q$, $q$Using scrolling capture and OCR to build step-by-step guides or extract text from screenshots.$q$, $q$Technical writers and support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$Quick visual sharing$q$, $q$Recording short screen captures or GIFs and sharing them instantly via CleanShot Cloud links.$q$, $q$Remote teams and content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$App + Cloud Basic$q$, $q$$29 one-time$q$, $q$One-time (optional $19/year renewal)$q$, NULL, $q$["Mac app license, yours to keep","1 year of free updates","1GB of Cloud storage","Shareable capture links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$App + Cloud Pro$q$, $q$$8/month (annual) or $10/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Always the latest app version","Unlimited Cloud storage","Custom domain & branding","Password protection & self-destructing links","Team management with SSO"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CleanShot X is a macOS-only screenshot and screen-recording app created by developer Luke Oslizlo and a small team based in Poland. It's designed as a more capable replacement for macOS's built-in capture tools, adding annotation, scrolling capture, OCR, and screen recording in a single app.$q$, $q$The app has built a strong following among Mac users through word of mouth, reviews, and its presence in the Setapp app bundle, despite the company not publishing formal corporate history or funding details.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capture features include a floating quick-access overlay after each screenshot, extensive annotation tools, automatic scrolling capture for full pages or long documents, and built-in OCR to extract text from an image.$q$, $q$Screen recording can be saved as a video file or an optimized GIF, and the app can automatically hide desktop icons and clutter so captures look clean without manual setup.$q$, $q$AI-assisted features include a smart blur tool that automatically detects and redacts sensitive data like emails, credit card numbers, and tokens, AI-generated alt text for accessibility, and a 'clean up' tool for removing background clutter from a screenshot.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core CleanShot X app is sold as a one-time $29 lifetime license per Mac, including one year of free updates, with an optional $19/year renewal to keep receiving updates after that.$q$, $q$CleanShot Cloud, the optional sharing and hosting service, includes a Basic tier (1GB storage) bundled with the app purchase and a Pro tier at $8/month billed annually ($10/month billed monthly) adding unlimited storage, custom domain branding, password-protected links, and team features. CleanShot X is also available through the Setapp app bundle.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e49a063e-cf60-43ca-ac4b-f2c2740a9b67', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Filler word removal$q$, $q$Automatically detects and cuts filler words like 'um' and 'uh' from recordings.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Background noise reduction$q$, $q$Removes background noise from raw audio without manual editing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Silence & mouth sound removal$q$, $q$Trims long silences and removes mouth sounds such as lip smacks and breathing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Multilingual support$q$, $q$Filler-word detection works across more than 40 spoken languages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Automatic transcription$q$, $q$Generates transcripts alongside the cleanup process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Video support$q$, $q$Processes video files in addition to standalone audio recordings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$API access$q$, $q$Custom API endpoints available on the enterprise plan for automated, high-volume processing.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Free trial with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Supports filler-word detection in 40+ languages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Unused subscription credits roll over up to 3x the monthly allowance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Works on both audio and video files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Credit-based pricing tied to processing hours can be harder to predict than a flat fee$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Focused narrowly on cleanup rather than full recording or publishing features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Per-hour cost is highest on the lowest tier, rewarding higher-volume commitments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Enterprise pricing for 200+ hours/month is not published and requires direct contact$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Is Cleanvoice free to try?$q$, $q$Yes, Cleanvoice offers a free trial with no credit card required before you commit to a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$How does Cleanvoice pricing work?$q$, $q$Pricing is credit-based and measured in hours of processed audio, available as one-time credit packs valid for two years or as monthly/annual subscriptions with set hourly allowances, starting around в‚¬11/month for 10 hours.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$What languages does Cleanvoice support?$q$, $q$Cleanvoice supports filler-word detection in more than 40 spoken languages, including English, Spanish, French, German, Portuguese, Italian, Dutch, Polish, Japanese, Korean, and Chinese.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Can Cleanvoice process video files?$q$, $q$Yes, Cleanvoice can process video files in addition to standalone audio recordings.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Who founded Cleanvoice?$q$, $q$Cleanvoice was founded in 2022 by Adrian Spataru, who is based in Graz, Austria, after struggling to find effective automated editing tools for his own podcast.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Does Cleanvoice offer an API?$q$, $q$Yes, custom API endpoints are available on Cleanvoice's enterprise plan for organizations processing 200 or more hours of audio per month.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Podcast post-production$q$, $q$Automatically cleaning up filler words, noise, and silences from raw podcast recordings before publishing.$q$, $q$Podcast creators and producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Video content cleanup$q$, $q$Removing filler words and background noise from spoken-word video content.$q$, $q$Video creators and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$High-volume automated processing$q$, $q$Integrating audio cleanup into a production pipeline via API for agencies or platforms processing many files.$q$, $q$Media agencies and audio/video platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Free Trial$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Try the service with no credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$10 Hours/Month$q$, $q$в‚¬11/month$q$, $q$Monthly or annual$q$, NULL, $q$["10 hours of audio processing","Filler word, noise, and silence removal","Transcription","Credits roll over up to 3x monthly limit"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$30 Hours/Month$q$, $q$в‚¬30/month$q$, $q$Monthly or annual$q$, NULL, $q$["30 hours of audio processing","Most popular tier","Same core features as other tiers"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$100 Hours/Month$q$, $q$в‚¬90/month$q$, $q$Monthly or annual$q$, NULL, $q$["100 hours of audio processing","Lowest effective per-hour rate","Same core features as other tiers"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$Custom (200+ hours)$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Custom API endpoints","Priority support","Custom pricing and billing"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cleanvoice is an AI-powered audio and video cleanup tool founded in 2022 by Adrian Spataru, based in Graz, Austria. It was built to solve a problem the founder faced firsthand while producing his own podcast: manually editing out filler words, silences, and noise was slow, and existing automated tools handled non-English accents poorly.$q$, $q$The product takes raw recordings and automatically removes common editing annoyances, letting creators skip the manual step of scrubbing through a waveform to clean up a recording before publishing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cleanvoice automatically detects and removes filler words, long silences, background noise, and mouth sounds like lip smacks and breathing, and it also offers automatic transcription alongside the cleanup process.$q$, $q$Filler-word detection covers more than 40 spoken languages, including English, Spanish, French, German, Portuguese, Italian, Dutch, Polish, Japanese, Korean, and Chinese, and Cleanvoice can process both audio-only files and video.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a9d84fa-11cb-4542-942a-2ec680e31383', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cleanvoice uses a credit-based pricing model measured in hours of processed audio, available both as one-time credit packs (valid for two years) and as recurring monthly or annual subscriptions with hourly allowances, with unused subscription credits rolling over up to three times the monthly limit.$q$, $q$Plans start around в‚¬11/month for 10 hours and scale up to roughly в‚¬90/month for 100 hours, with a custom-priced plan for organizations needing 200+ hours per month that adds API endpoints and priority support. New users can try the service for free without a credit card.$q$]::text[], 2);
