-- в”Ђв”Ђ CKAN в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$CKAN is a free, open-source data management system for building open data portals, used by governments and organizations worldwide to publish, search, and share datasets.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (Free, self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom (Open Knowledge Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CKAN: Open-Source Data Management System$q$, seo_title),
  seo_meta_description = COALESCE($q$CKAN is a free, open-source data catalog and portal platform that governments and organizations worldwide use to publish, search, and share open datasets.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CKAN (Comprehensive Knowledge Archive Network) is a free, open-source data management system used to build and run data catalog and open-data portal websites. It originated from work by economist Rufus Pollock and the Open Knowledge Foundation (OKF), a UK non-profit founded in Cambridge in 2004 and now headquartered in London; the first public CKAN release dates to 2006, and the codebase is still maintained by OKF with a broad community of contributors. CKAN is written primarily in Python (Flask/Pylons), stores metadata in PostgreSQL, and uses Apache Solr for search indexing. It is distributed under the GNU Affero General Public License v3 (AGPL-3.0), so the software itself carries no license fee. Organizations self-host CKAN on their own servers or cloud infrastructure, or pay third-party vendors such as Datopian, Link Digital, or Keitaro for managed hosting, migration, and support contracts; there is no official hosted SaaS product from OKF itself. CKAN's core function is letting publishers register datasets with structured metadata, upload or link to data files (CSV, Excel, GeoJSON, PDF, and more), and expose that data through a searchable, filterable web catalog plus a RESTful JSON Action API that developers use to query, retrieve, and programmatically manage datasets and organizations. Built-in capabilities include dataset versioning and revision history, resource previews and lightweight visualizations (bar, line, and pie charts, and maps for tabular or geospatial resources), user and organization management with role-based access control, and activity streams for tracking changes. A modular extension system, with more than 60 community-maintained extensions, adds capabilities such as web harvesting from other catalogs, a DataStore and DataPusher for making tabular data queryable via API, analytics, custom theming, and federation so multiple CKAN instances can share and aggregate datasets across a network of portals. CKAN is best known as the software running large government open-data catalogs, including data.gov (United States), data.gov.uk (United Kingdom), open.canada.ca, and numerous city, state, national, and international data portals, as well as humanitarian and research-data platforms such as the Humanitarian Data Exchange (data.humdata.org). Its practical audience is government agencies, research institutions, NGOs, and organizations that need to publish structured datasets to the public or internal stakeholders in a searchable, standardized way вЂ” not individual consumers or small businesses. Because CKAN requires server administration, database management, and Solr search-index tuning (particularly at scale), it generally needs a technical team or a managed-hosting vendor to operate day to day. Pricing is therefore best understood as free software plus paid infrastructure and optional support: total cost of ownership depends on hosting and vendor choices rather than any fee charged by the CKAN project. Adjacent or competing tools include Socrata, OpenDataSoft, and DKAN (a Drupal-based, CKAN-inspired alternative), but CKAN remains one of the most widely deployed open-source options for institutional open-data publishing because of its maturity, its API, and its adoption across major national data portals.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e8f32075-0ef5-42f6-8b94-a8c3c8544c46';

