-- в”Ђв”Ђ Clair в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Clair is a free, open-source vulnerability scanner that statically analyzes container images against CVE databases to secure registries and CI/CD pipelines.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (Free)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, US (originally CoreOS; now maintained under Red Hat)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clair: Open-Source Container Vulnerability Scanner$q$, seo_title),
  seo_meta_description = COALESCE($q$Clair is a free, open-source tool that statically scans container images for known vulnerabilities, powering security checks for registries like Quay.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clair is a free, open-source vulnerability scanner for container images, originally announced by CoreOS in November 2015 and later brought under Red Hat's stewardship following Red Hat's 2018 acquisition of CoreOS. The project is hosted in the quay/clair repository on GitHub and is licensed under Apache 2.0, meaning there is no cost to download, run, or modify it. Clair works by statically analyzing the contents of OCI and Docker container images: it indexes the packages and libraries present in each image layer, then matches those packages against vulnerability data pulled continuously from sources such as the National Vulnerability Database (NVD) and distribution-specific feeds covering Red Hat Enterprise Linux, Alpine, Ubuntu, Debian, Oracle Linux, Photon OS, and SUSE, as well as language ecosystems like Java, Python, Go, and JavaScript. Architecturally, Clair v4 is split into cooperating microservices вЂ” an indexer that parses image layers, a matcher that compares indexed packages against known vulnerability data, a notifier that fires webhooks when previously scanned images gain newly discovered CVE matches, and an API layer exposing REST and gRPC endpoints вЂ” though it can also run in a more monolithic mode for smaller deployments, CI pipelines, or air-gapped/disconnected environments. Clair's most prominent real-world use is as the vulnerability-scanning backend for Red Hat Quay and the public Quay.io container registry, where it continuously re-checks stored images as new vulnerabilities are published so that image owners get an up-to-date view of their security exposure without re-uploading anything. It has also been used by other security tooling in the container ecosystem, such as StackRox, and is commonly integrated into CI/CD pipelines to fail builds or flag images that contain known-vulnerable packages before they reach production. Because Clair is infrastructure software rather than a consumer application, it has no subscription tiers, seats, or account system of its own; organizations run it themselves (typically alongside a container registry) or consume it indirectly through a product like Quay that embeds it. There is no official managed cloud version of Clair sold directly by its maintainers, so adopting it requires the same kind of operational investment as any self-hosted open-source security tool: provisioning the microservices, connecting a datastore, and keeping vulnerability feeds updated. Its target users are platform engineering, DevSecOps, and security teams responsible for container image supply-chain security, rather than individual developers looking for a point-and-click scanner. Clair competes with tools such as Trivy, Grype, and Anchore Engine in the open-source container-scanning space, and with commercial platforms like Snyk Container or Prisma Cloud for organizations wanting a fully managed alternative; Clair's differentiators are its deep integration with the Quay registry ecosystem, its Apache 2.0 licensing, and its long operational track record at the scale of a public container registry.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'caec6253-7f1b-408d-968e-1099f0367648';

