-- в”Ђв”Ђ Claude в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Claude is Anthropic's family of AI assistant models and apps for conversation, coding, research, and agentic tasks, available via web, desktop, mobile, and API.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Subscription / Usage-based API$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $17/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$~5,000 employees (est., 2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Claude: Anthropic's AI Assistant Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Claude is Anthropic's AI assistant for chat, coding, and research, offering a free tier plus Pro, Max, Team, and Enterprise plans and a usage-based API.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Claude is the AI assistant product family built by Anthropic, an AI safety and research company founded in January 2021 by siblings Dario Amodei (CEO) and Daniela Amodei (President), along with several other former OpenAI researchers, and headquartered in San Francisco, California. Anthropic operates as a public benefit corporation and has grown rapidly since its founding, raising large funding rounds and reaching a valuation reported around several hundred billion dollars in 2026, with an estimated headcount in the low thousands. Claude is accessible through a free consumer web and mobile chat app, dedicated desktop and mobile apps, a developer-facing API (available directly through Anthropic's platform as well as through Amazon Bedrock and Google Cloud Vertex AI), and enterprise integrations. Anthropic offers multiple Claude model families spanning different capability and cost tiers вЂ” commonly described as smaller/faster models optimized for speed and cost, and larger/more capable models optimized for complex reasoning, coding, and long-running agentic tasks вЂ” and these models are used both directly in Claude's own apps and by third-party developers building on the API. Consumer pricing, per Anthropic's official pricing page, includes a Free plan ($0) offering web and mobile chat, code generation, content creation, web search, memory, and file creation with usage limits; a Pro plan priced at $17/month billed annually (or $20/month billed monthly) that adds higher usage limits, access to Claude Code (Anthropic's agentic coding tool), unlimited projects, research features, and access to multiple Claude models; and a Max plan starting at $100/month offering substantially higher usage caps (described as 5x or 20x Pro-level usage), higher output limits, and priority access during periods of high demand. For organizations, Clari-style seat-based Team plans are priced at $20-25/month per standard seat (annual vs. monthly billing) or $100-125/month per premium seat, covering teams of roughly 2 to 150 people with centralized billing, admin controls, and SSO; Enterprise plans are custom-quoted based on seat count plus API usage and add SCIM provisioning, audit logs, role-based access control, configurable data retention, HIPAA-ready options, IP allowlisting, and a compliance API. Beyond the chat interface, Anthropic has built out an ecosystem of specialized product surfaces under the Claude brand вЂ” including Claude Code for terminal- and IDE-based agentic software development, and integrations with tools like Microsoft 365 вЂ” reflecting a broader push from single-turn chat toward multi-step, tool-using "agentic" workflows that can read files, run code, browse the web, and act across a session rather than just answer one prompt at a time. Claude's primary audience spans individual knowledge workers and developers using the free or Pro tiers for everyday writing, research, and coding assistance; power users and small teams on Max or Team plans running heavier workloads or needing collaboration features; and enterprises building regulated or large-scale AI applications through custom Enterprise agreements or direct API usage, where cost is governed by input/output token consumption per model rather than a flat subscription. Anthropic differentiates Claude primarily on its safety-focused development approach, long-context handling, coding and agentic-task performance, and enterprise compliance features, competing most directly against OpenAI's ChatGPT/GPT models and Google's Gemini in the general-purpose AI assistant and API market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4648f65b-d55e-4ed8-ad0d-c40b3343b03c';

