-- в”Ђв”Ђ Clay в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Clay is an AI-powered go-to-market platform that combines 100+ data providers and AI research agents in a spreadsheet-style workflow builder for sales prospecting.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based (credits)$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from ~$149-185/month)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Clay: AI-Powered Go-to-Market Data Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Clay is an AI-powered prospecting platform combining 100+ data providers and AI agents in a spreadsheet interface for enrichment and outbound sales.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Clay is a go-to-market data and workflow platform built for sales, marketing, and revenue operations teams to research, enrich, and act on lead and account data. The company was founded in June 2017 by Kareem Amin (CEO) and Nicolae Rusan, with Varun Anand joining as a co-founder in 2021, and is headquartered in New York City. Clay began with a broader ambition around programmable data workflows before narrowing its focus, over several product iterations, to become what its founders describe as an integrated development environment for go-to-market teams. The product's core interface is a spreadsheet-like table where each row represents a lead, company, or other record, and each column can run a data-enrichment step: pulling data from over 100 third-party providers (covering firmographic, technographic, contact, intent, and signal data), running web research via an AI agent feature called Claygent that can browse the web and extract specific information, or triggering actions like sending emails, updating a CRM, or posting to an ad platform's custom audience. Clay's pricing is credit-based and tiered: a Free plan includes 500 actions and 100 data credits per month with unlimited seats and up to 200 rows per table; a Launch plan starts around $149-185/month (varying by billing term and credit volume) with roughly 15,000 actions and 3,000 data credits per month, phone-number enrichment, job-change and buying-signal tracking, and up to 50,000 rows per table; a Growth plan starts around $446-495/month with roughly 40,000 actions and 6,000 data credits per month, CRM auto-sync, HTTP API and webhook integrations, and ad-platform audience pushes; and a custom-quoted Enterprise plan adds unlimited ad audiences, SSO, role-based access control, and dedicated support for 200,000+ monthly actions. Clay has raised significant venture funding, including rounds from Sequoia Capital and CapitalG (Google's growth-equity arm), reaching a valuation reported around $3.1 billion in 2026 with annual recurring revenue reported in the range of tens to roughly $100 million and a rapidly growing customer base. Its target users are go-to-market, sales development, and RevOps teams at B2B companies that need to combine multiple data sources and automate outbound research and personalization at scale, rather than individual consumers or non-technical end users, though Clay is explicitly designed to require no traditional coding вЂ” workflows are built by chaining together enrichment columns, formulas, and integrations in the spreadsheet interface. Clay competes with tools such as Apollo.io, ZoomInfo, and Clearbit for data enrichment, and with workflow-automation platforms like Zapier or Make for its automation layer, but differentiates itself by combining many data providers behind a single interface with a table-based, low-code workflow builder purpose-built for outbound sales and marketing use cases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c5a72856-c532-4882-bce1-c4c3664d929b';

