-- в”Ђв”Ђ Cleanfeed в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Cleanfeed is a browser-based remote recording platform for broadcast-quality podcast and radio interviews, used by broadcasters like the BBC and NPR.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $12-23/month)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cleanfeed: Browser-Based Remote Recording$q$, seo_title),
  seo_meta_description = COALESCE($q$Cleanfeed is a browser-based platform for broadcast-quality remote podcast and radio recording, offering a free Lite tier and a paid Pro tier.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cleanfeed is a browser-based remote audio recording platform built for podcasters, radio producers, and broadcast professionals who need to record interviews with remote guests at broadcast quality. The company was founded by Mark Hills and Marc Bakos and is headquartered in London, United Kingdom, with the business incorporated in 2015 and generally cited as founded around 2014. Cleanfeed's core technical differentiator is that it runs entirely in a web browser using direct browser-to-browser (peer-to-peer style) audio connections rather than routing audio through a media server, which keeps latency low and lets guests join a recording session via a simple link with no app download, plugin install, or account creation required on their end. The platform is used by major broadcasters, including the BBC and NPR, alongside independent podcasters and commercial production houses, for recording remote interviews destined for radio broadcast or podcast publication. Cleanfeed offers two pricing tiers: Cleanfeed Lite is free and supports browser-based remote recording for up to three participants with no limit on recording length, covering commercial use; Cleanfeed Pro is a paid subscription (listed starting around $23/month standard, with discounted rates around $12/month on annual billing, and further discounts for educational, charity, or personal use) that unlocks multitrack recording (separate, synced WAV files per participant at up to 48kHz), noise removal and echo cancellation, audio repair tools, a live channel mixer, support for groups larger than three participants, higher bitrates (up to 256kbps mono or 320kbps stereo), studio tools such as intros, idents, and jingle beds, privacy controls and personalized invite links, and support for multiple local audio input devices. An Enterprise/Education tier is available for organizations needing five or more Cleanfeed Pro licenses, offering consolidated billing, customization, and branding options through direct sales contact rather than self-serve checkout. Cleanfeed's target users split into two groups: broadcast and radio professionals who need dependable, high-fidelity remote recording integrated into an existing production workflow, and independent podcasters or commercial producers who need an accessible, no-install way to record remote guests without asking them to download separate recording software. It differs from competitors such as Riverside.fm, Squadcast, and Zencastr вЂ” which tend to emphasize video recording, automated post-production, and content-repurposing features вЂ” by focusing more narrowly on audio recording quality, low latency, and simplicity, reflecting its origins serving traditional radio and broadcast newsrooms before the modern podcasting boom.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7b313f97-5726-4dc3-822e-2919a68cf2b3';

