-- в”Ђв”Ђ Cleanvoice в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Cleanvoice is an AI audio and video editing tool that automatically removes filler words, background noise, mouth sounds, and silences from podcast recordings.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based (credits)$q$, pricing_model),
  starting_price = COALESCE($q$Free trial (paid from ~в‚¬11/month)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Graz, Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cleanvoice: AI Podcast Audio Cleanup Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Cleanvoice is an AI tool that automatically removes filler words, noise, and silences from podcast audio and video, with plans from around в‚¬11/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cleanvoice is an AI-powered audio and video editing tool focused on automatically cleaning up raw podcast and voice recordings. It was founded in 2022 by Adrian Spataru, who is based in Graz, Austria, and started the company after struggling to find effective automated editing tools while producing his own podcast; frustration with the limitations of existing options for handling filler words and non-English accents was a direct motivation for building Cleanvoice. The product's core function is to take a raw, unedited recording and automatically strip out common editing annoyances вЂ” filler words ('um,' 'uh,' and similar), long silences, background noise, and mouth sounds such as lip smacks and breathing вЂ” without requiring the user to manually scrub through a waveform in a traditional audio editor. Cleanvoice supports filler-word detection across more than 40 spoken languages, including English, Spanish, French, German, Portuguese, Italian, Dutch, Polish, Japanese, Korean, and Chinese, reflecting its founder's original motivation around non-English accent support, and it also offers automatic transcription and works on video files as well as pure audio. Cleanvoice's pricing is credit-based (measured in hours of processed audio) and offered both as one-time, pay-as-you-go credit packs valid for two years (for example, roughly $11 for 5 hours or $45 for 30 hours) and as recurring monthly or annual subscriptions covering set hourly allowances (for example, roughly в‚¬11-в‚¬90 per month for 10 to 100 hours, with lower effective per-hour rates at higher tiers, and unused credits rolling over up to three times the monthly allotment). A custom-priced plan is available for organizations processing 200 or more hours per month, adding custom API endpoints, priority support, and custom billing, and the company states this enterprise tier is used by more than 30 brands. New users can try Cleanvoice for free without providing a credit card before committing to a paid plan. Cleanvoice's target users are podcast creators, video creators, and audio/video production teams who want to reduce the time spent on manual editing, as well as agencies and platforms that process audio at volume and want API-based automation rather than a manual editing interface for every file. It differentiates itself from broader all-in-one podcast platforms (such as Descript or Riverside.fm, which combine recording, editing, and publishing) by focusing specifically and narrowly on the automated cleanup step of the editing workflow, making it usable as a standalone tool or as a processing step layered on top of recordings made elsewhere, including via its API for developers who want to build cleanup into their own production pipeline.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9a9d84fa-11cb-4542-942a-2ec680e31383';

